from pydantic import BaseModel, Field
from typing import Dict, List, Optional, Any
from mcp.server.fastmcp import FastMCP

# Section 1: Schema
class Phonetic(BaseModel):
    """Phonetic representation with optional audio."""
    text: str = Field(..., description="Phonetic spelling notation")
    audio: str = Field(default="", description="URL to audio pronunciation file")

class Definition(BaseModel):
    """Single definition entry."""
    definition: str = Field(..., description="Semantic definition text")
    example: str = Field(default="", description="Usage example sentence")
    synonyms: List[str] = Field(default=[], description="Similar meaning words")
    antonyms: List[str] = Field(default=[], description="Opposite meaning words")

class Meaning(BaseModel):
    """Meanings grouped by part of speech."""
    partOfSpeech: str = Field(..., description="Grammatical category")
    definitions: List[Definition] = Field(default=[], description="Definition entries")

class DictionaryEntry(BaseModel):
    """Complete dictionary entry for a word."""
    word: str = Field(..., description="Canonical form of the word")
    phonetic: str = Field(default="", description="IPA phonetic transcription")
    phonetics: List[Phonetic] = Field(default=[], description="Phonetic representations")
    origin: str = Field(default="", description="Etymological origin")
    meanings: List[Meaning] = Field(default=[], description="Semantic definitions")

class DictionaryScenario(BaseModel):
    """Main scenario model for dictionary data."""
    entries: Dict[str, List[DictionaryEntry]] = Field(default={}, description="Dictionary entries by word")

Scenario_Schema = [Phonetic, Definition, Meaning, DictionaryEntry, DictionaryScenario]

# Section 2: Class
class DictionaryAPI:
    def __init__(self):
        """Initialize dictionary API with empty state."""
        self.entries: Dict[str, List[DictionaryEntry]] = {}

    def load_scenario(self, scenario: dict) -> None:
        """Load scenario data into the API instance."""
        model = DictionaryScenario(**scenario)
        self.entries = model.entries

    def save_scenario(self) -> dict:
        """Save current state as scenario dictionary."""
        return {
            "entries": {word: [entry.model_dump() for entry in entries] for word, entries in self.entries.items()}
        }

    def get_definition(self, word: str, language: str) -> dict:
        """Retrieve comprehensive dictionary definitions."""
        key = f"{language}:{word.lower()}"
        entries = self.entries.get(key, [])
        return {"entries": [entry.model_dump() for entry in entries]}

    def get_synonyms(self, word: str, language: str) -> dict:
        """Retrieve synonyms organized by part of speech."""
        key = f"{language}:{word.lower()}"
        entries = self.entries.get(key, [])
        groups = []
        for entry in entries:
            for meaning in entry.meanings:
                synonyms = []
                for definition in meaning.definitions:
                    synonyms.extend(definition.synonyms)
                if synonyms:
                    groups.append({"part_of_speech": meaning.partOfSpeech, "synonyms": list(set(synonyms))})
        return {"synonym_groups": groups}

    def get_antonyms(self, word: str, language: str) -> dict:
        """Retrieve antonyms organized by part of speech."""
        key = f"{language}:{word.lower()}"
        entries = self.entries.get(key, [])
        groups = []
        for entry in entries:
            for meaning in entry.meanings:
                antonyms = []
                for definition in meaning.definitions:
                    antonyms.extend(definition.antonyms)
                if antonyms:
                    groups.append({"part_of_speech": meaning.partOfSpeech, "antonyms": list(set(antonyms))})
        return {"antonym_groups": groups}

    def get_pronunciation(self, word: str, language: str) -> dict:
        """Retrieve phonetic pronunciation guides."""
        key = f"{language}:{word.lower()}"
        entries = self.entries.get(key, [])
        if not entries:
            return {"word": word, "phonetic": "", "audio_url": "", "alternative_pronunciations": []}
        entry = entries[0]
        audio_url = ""
        alternatives = []
        for phonetic in entry.phonetics:
            if phonetic.audio and not audio_url:
                audio_url = phonetic.audio
            if phonetic.text:
                alternatives.append(phonetic.text)
        return {
            "word": entry.word,
            "phonetic": entry.phonetic,
            "audio_url": audio_url,
            "alternative_pronunciations": alternatives
        }

    def get_etymology(self, word: str, language: str) -> dict:
        """Retrieve etymological origin."""
        key = f"{language}:{word.lower()}"
        entries = self.entries.get(key, [])
        etymology = entries[0].origin if entries else ""
        return {"etymology": etymology}

